{
	int fd;
	if (xb->modified)
		return \"unsaved changes present\";
	if (*arg)
		xlw = atoi(arg);
	else
		xlw = xcols;
	lbuf_free(xb);
	xb = lbuf_make();
	readfile()
	ex_bufpostfix(ex_buf, 1);
	syn_setft(xb_ft);
	return NULL;
}

